import{_ as e,o as a,c as i,ae as o}from"./chunks/framework.B6gjLfeO.js";const c=JSON.parse('{"title":"TikTok For Business Overview","description":"","frontmatter":{"title":"TikTok For Business Overview","slug":"tiktok-for-business"},"headers":[],"relativePath":"marketer-hub/tiktok-for-business.md","filePath":"marketer-hub/tiktok-for-business.md"}'),r={name:"marketer-hub/tiktok-for-business.md"};function n(s,t,d,h,l,u){return a(),i("div",null,[...t[0]||(t[0]=[o('<p><em>[Image: 1211]</em></p><div class="tip custom-block"><p class="custom-block-title">Branch Certified Partner</p><ul><li><a href="./tiktok-for-business.html#overview"><strong>Overview</strong></a> (this page)</li><li><a href="./enable-tiktok-for-business.html">Enable TikTok For Business</a></li><li><a href="./tiktok-skadnetwork.html">TikTok SKAdNetwork</a></li><li><a href="./tiktok-data-reporting.html">TikTok Data &amp; Reporting</a></li></ul></div><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">Different Integrations</p><p>Branch has two module integrations with TikTok For Business: one works with TikTok using trackers to capture attribution information, and the other works with TikTok as a self-attributing network (SAN). This article is about setting up the SAN integration.<br> Inform your TikTok representative when you activate the SAN integration in Branch.</p><p><strong>IMPORTANT:</strong> During the transition to the SAN integration, do not deactivate the <a href="./tiktok-for-business.html">non-SAN module</a></p></div><p>Brand new features are emerging in the industry, and TikTok For Business can now support attribution standards via an API endpoint and an Ad Link. As a Mobile Measurement Partner (MMP), Branch can connect with TikTok For Business through a back-end connection through set endpoints. By combining TikTok&#39;s self-attribution network (SAN) data with Branch&#39;s exclusive cross-channel Link Graph, you will uncover the true drivers of user activity across every ad network and channel. Additionally, you&#39;ll be able to compare your campaign performance directly on the Branch Dashboard.</p><p><strong>Note:</strong> The legacy non-SAN integration will still be functional until all apps can transition to the new SAN integration.</p><h2 id="how-does-it-work" tabindex="-1">How does it work? <a class="header-anchor" href="#how-does-it-work" aria-label="Permalink to &quot;How does it work?&quot;">​</a></h2><ol><li><p>Branch connects with TikTok For Business through an MMP API Endpoint through account authentication in the Branch Dashboard.</p></li><li><p>Events are configured to send from Branch to TikTok For Business.</p></li><li><p>Once campaigns are launched, users see an ad to download your app through the different placements run by TikTok For Business.</p></li><li><p>User installs the app and performs in-app events (ex. PURCHASE)</p><ul><li>The Branch SDK captures the app install and downstream events.</li></ul></li><li><p>Branch communicates with TikTok For Business through the MMP API Endpoint and sends TikTok For Business data about the conversion.</p><ol><li>Branch will also send data from Ad Links for reporting; thus, maximizing attribution coverage</li></ol></li><li><p>TikTok For Business claims conversions by sending the click/impression campaign data that sourced it to Branch.</p></li><li><p>The Branch Dashboard will update reports for you to be able to compare and measure ad campaigns across placements, ad type, etc.</p></li></ol><h2 id="tiktok-for-business-campaign-support" tabindex="-1">TikTok For Business Campaign Support <a class="header-anchor" href="#tiktok-for-business-campaign-support" aria-label="Permalink to &quot;TikTok For Business Campaign Support&quot;">​</a></h2><h3 id="supported-placements" tabindex="-1">Supported Placements <a class="header-anchor" href="#supported-placements" aria-label="Permalink to &quot;Supported Placements&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Placement</th></tr></thead><tbody><tr><td>TikTok</td></tr><tr><td>News Feed App Series</td></tr><tr><td>Pangle</td></tr><tr><td>Helo</td></tr></tbody></table><h2 id="limitations" tabindex="-1">Limitations <a class="header-anchor" href="#limitations" aria-label="Permalink to &quot;Limitations&quot;">​</a></h2><h2 id="data-sharing" tabindex="-1">Data Sharing <a class="header-anchor" href="#data-sharing" aria-label="Permalink to &quot;Data Sharing&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Data Purge &amp; Sharing</p><ul><li><p>Branch will purge the last-attributed data fields after 60 days</p></li><li><p>TikTok For Business data is not shared with third parties</p><ul><li>Data/analytics partners integrated with Branch will not receive TikTok For Business data (both click and view data)</li></ul></li></ul></div><p>Branch keeps all of the event data that was sent from TikTok For Business on the event, such as mobile device ID. Branch wipes all data that we would not have without TikTok For Business sharing, such as campaign info.</p><h3 id="view-through-data" tabindex="-1">View-Through Data <a class="header-anchor" href="#view-through-data" aria-label="Permalink to &quot;View-Through Data&quot;">​</a></h3><p>You may access some view-through attributed conversion data through Branch&#39;s <a href="./custom-exports-api.html">Custom Exports API</a> and <a href="./webhooks.html">Webhooks</a> using the following fields:</p><table tabindex="0"><thead><tr><th>EO Field</th><th>Value</th></tr></thead><tbody><tr><td><code>last_attributed_touch_type</code></td><td>IMPRESSION</td></tr><tr><td><code>last_attributed_touch_data_dollar_3p</code></td><td>a_tiktok</td></tr></tbody></table><p>When conversions are attributed to TikTok ad campaigns, you exports/webhooks will populate the following fields:</p><table tabindex="0"><thead><tr><th>Field</th><th>Value</th></tr></thead><tbody><tr><td>Ad Partner Name</td><td>TikTok For Business SAN</td></tr><tr><td>Ad Partner $3p</td><td>a_tiktok</td></tr><tr><td>Channel</td><td>TikTok For Business SAN</td></tr><tr><td>Attribution Touch Type</td><td>IMPRESSION</td></tr><tr><td>Attribution Touch Timestamp</td><td>Unix Timestamp only day, month, and year. Hour, minute, and second are removed.</td></tr></tbody></table><p>Note: Any other attributed touch fields will still be reported as null.</p><p>When viewing impression-attributed data and reports in the Branch Dashboard, only aggregate data is available.</p><h2 id="ios-attribution" tabindex="-1">iOS Attribution <a class="header-anchor" href="#ios-attribution" aria-label="Permalink to &quot;iOS Attribution&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Ad Type</th><th>Platform Flow</th><th>App Installed</th><th>Publisher</th><th>Advertiser</th><th></th><th>SKAN Availability</th><th>Direct Deep Linking</th><th>Deferred Deep Linking</th><th></th></tr></thead><tbody><tr><td>Opt-In</td><td>Opt-Out</td><td>Advertiser Opt-In</td><td>Advertiser Opt-Out</td><td></td><td></td><td></td><td></td><td></td><td></td></tr><tr><td>TikTok App Install</td><td>App to App</td><td>No</td><td>Opt-In</td><td>Device-level Attribution via <a href="./advertising-identifiers-for-attribution.html#ios-identifiers">IDFA</a> (SAN)</td><td>No Attribution</td><td>✔</td><td>N/A</td><td>✔</td><td>✔</td></tr><tr><td>Opt-Out</td><td>No Attribution</td><td>No Attribution</td><td>✔</td><td>N/A</td><td>✔</td><td>✔</td><td></td><td></td><td></td></tr><tr><td>TikTok App Engagement</td><td>Yes</td><td>Opt-In</td><td>Device-level Attribution via <a href="./advertising-identifiers-for-attribution.html#ios-identifiers">IDFA</a> (SAN)</td><td>No Attribution</td><td>✘</td><td>✔*</td><td>N/A</td><td>N/A</td><td></td></tr><tr><td>Opt-Out</td><td>No Attribution</td><td>No Attribution</td><td>✘</td><td>✔*</td><td>N/A</td><td>N/A</td><td></td><td></td><td></td></tr></tbody></table><p><strong>*Deep Linking assumes the ad unit is using Branch</strong> <a href="./ad-links.html"><strong>Ad Links</strong></a></p><p>For additional information on iOS 14 Impact on TikTok, visit the <a href="./ios-14-faqs.html#other-networks-ios-14">iOS 14 FAQs</a></p>',26)])])}const k=e(r,[["render",n]]);export{c as __pageData,k as default};
